    public static void main(String[] args) {

        // Create a Scanner object to read input from the console
        Scanner scan = new Scanner(System.in);

        // Read the integer X from input
        int X = scan.nextInt();

        // Read the integer N from input, which represents the size of the array
        int N = scan.nextInt();

        // Initialize an array M of size N to store the integers
        int M[] = new int[N];

        // Initialize variables K and Y to 0
        int K = 0;
        int Y = 0;

        // Loop to read N integers into the array M
        for (int i = 0; i < N; i++) {
            M[i] = scan.nextInt();

            // If the current element is equal to X, set K and Y to 1
            if (M[i] == X) {
                K = 1;
                Y = 1;
            }
        }

        // Initialize P with the value of X
        int P = X;

        // Initialize C to 1, which will be used as a flag
        int C = 1;

        // Sort the array M in ascending order
        Arrays.sort(M);

        // Loop to find the closest number to X in the array M
        for (int i = 0; i < N && K == 1 && C == 1; i++) {
            C = 0; // Reset C to 0
            K = 0; // Reset K to 0

            // Loop through the array M from the end to the beginning
            for (int j = N - 1; j >= 0 && K == 0; j--) {
                // Check if the current element is equal to X + i
                if (M[j] == X + i) {
                    C = 1; // Set C to 1
                    P = M[j]; // Update P to the current element
                }

                // Check if the current element is equal to X - i
                if (M[j] == X - i) {
                    K = 1; // Set K to 1
                    P = M[j]; // Update P to the current element
                }
            }
        }

        // Output the result based on the values of P, X, Y, K, and C
