public class Main {
  public static void main(String[] args) throws Exception {
    // Create a FastScanner object to read input from the standard input stream
    FastScanner sc = new FastScanner(System.in);

    // Read a long integer value from the input
    long x = sc.nextLong();

    // Initialize a counter to track the number of years
    int i = 0;

    // Initialize the initial amount of money
    double m = 100;

    // Loop until the amount of money is at least x
    while(m < x) {
      // Increase the money by 1% each year
      m *= 1.01;

      // Use Math.floor to round down to the nearest whole number
      m = Math.floor(m);

      // Increment the year counter
      ++i;
    }

    // Output the number of years it takes for the money to reach or exceed x
    System.out.println(i);
  }
}

class FastScanner {
  // InputStream to read data from
  private final InputStream in;

  // Buffer to store bytes read from the input stream
  private final byte[] buffer = new byte[1024];

  // Pointer to the current position in the buffer
  private int ptr = 0;

  // Number of bytes currently in the buffer
  private int buflen = 0;

  // Constructor to initialize the FastScanner with an InputStream
  public FastScanner(InputStream source) {
    in = source;
  }

  // Check if there is another byte available in the buffer
  private boolean hasNextByte() {
    if (ptr < buflen) {
      return true;
    } else {
      ptr = 0;
      try {
        // Read more bytes into the buffer
        buflen = in.read(buffer);
      } catch (IOException e) {
        e.printStackTrace();
      }
      // Return false if no more bytes are available
      if (buflen <= 0) {
        return false;
      }
    }
    return true;
  }

  // Read the next byte from the buffer
  private int readByte() {
    if (hasNextByte()) return buffer[ptr++];
    else return -1;
  }

  // Check if a character is printable
  private static boolean isPrintableChar(int c) {
    return 33 <= c && c <= 126;
  }

  // Check if there is another token available
  public boolean hasNext() {
    // Skip non-printable characters
    while (hasNextByte() && !isPrintableChar(buffer[ptr])) ptr++;
    return hasNextByte();
  }

  // Read the next token as a String
  public String next() {
    if (!hasNext()) throw new NoSuchElementException();
    StringBuilder sb = new StringBuilder();
    int b = readByte();
    // Append characters to the StringBuilder until a non-printable character is encountered
    while (isPrintableChar(b)) {
      sb.appendCodePoint(b);
      b = readByte();
    }
    return sb.toString();
  }

  // Read the next token as a long integer
  public long nextLong() {
    if (!hasNext()) throw new NoSuchElementException();
    long n = 0;
    boolean minus = false;
    int b = readByte();
    // Check for a negative sign
    if (b == '-') {
      minus = true;
      b = readByte();
    }
    // Ensure the first character is a digit
    if (b < '0' || '9' < b) {
      throw new NumberFormatException();
    }
    // Parse the number
    while (true) {
      if ('0' <= b && b <= '9') {
        n *= 10;
        n += b - '0';
      } else if (b == -1 || !isPrintableChar(b)) {
        return minus ? -n : n;
      } else {
        throw new NumberFormatException();
      }
      b = readByte();
    }
  }

  // Read the next token as an integer
  public int nextInt() {
    long nl = nextLong();
    // Check if the long value fits within the integer range
    if (nl < Integer.MIN_VALUE || nl > Integer.MAX_VALUE)
      throw new NumberFormatException();
    return (int) nl;
  }

  // Read the next token as a double
  public double nextDouble() {
    return Double.parseDouble(next());
  }
}

