// Suppress warnings for unused imports and variables
@SuppressWarnings("unused")
public class Main {
    // Name of the input file
    String fileName = "input.txt";
    // Debug flag to switch between file input and standard input
    final boolean isDebug = false;

    // FastScanner for efficient input reading
    FastScanner in = new FastScanner(System.in);
    // PrintWriter for efficient output writing
    PrintWriter out = new PrintWriter(System.out);
    // Constant for modulo operations
    final int MOD = (int)1e9+7;
    // Constant representing infinity for long values
    final long INF = Long.MAX_VALUE / 2;

    // Main logic of the program
    void solve() throws Exception {
        // Read a string from input
        String S = in.nextStr();
        // Iterate over the string to check for consecutive identical characters
        for(int i = 1; i < S.length(); i++) {
            // If two consecutive characters are the same, print "Bad" and exit
            if(S.charAt(i-1) == S.charAt(i)) {
                out.println("Bad");
                return;
            }
        }
        // If no consecutive identical characters are found, print "Good"
        out.println("Good");
    }

    // Entry point of the program
    public static void main(String[] args) throws Exception {
        // Create an instance of Main and call the method m()
        new Main().m();
    }

    // Method to handle input source and call the solve method
    void m() throws Exception {
        // If debug mode is enabled, read input from a file
        if(isDebug) in = new FastScanner(new FileInputStream(fileName));
        // Solve the problem
        solve();
        // Flush the output buffer
        out.flush();
    }
}

// Custom scanner class for fast input reading
class FastScanner {
    // Reader object for input
    Reader input;

    // Constructor for standard input
    FastScanner() {this(System.in);}
    // Constructor for input from a stream
    FastScanner(InputStream stream) {this.input = new BufferedReader(new InputStreamReader(stream));}

    // Method to read the next integer from input
    int nextInt() {return (int) nextLong();}

    // Method to read the next long integer from input
    long nextLong() {
        try {
            int sign = 1;
            int b = input.read();
            // Skip non-numeric characters
            while ((b < '0' || '9' < b) && b != '-' && b != '+') {
                b = input.read();
            }
            // Handle negative numbers
            if (b == '-') {
                sign = -1;
                b = input.read();
            } else if (b == '+') {
                b = input.read();
            }
            // Read the number
            long ret = b - '0';
            while (true) {
                b = input.read();
                if (b < '0' || '9' < b) return ret * sign;
                ret *= 10;
                ret += b - '0';
            }
        } catch (IOException e) {
            e.printStackTrace();
            return -1;
        }
    }

    // Method to read the next double from input
    double nextDouble() {
        try {
            double sign = 1;
            int b = input.read();
            // Skip non-numeric characters
            while ((b < '0' || '9' < b) && b != '-' && b != '+') {
                b = input.read();
            }
            // Handle negative numbers
            if (b == '-') {
                sign = -1;
                b = input.read();
            } else if (b == '+') {
                b = input.read();
            }
            // Read the integer part
            double ret = b - '0';
            while (true) {
                b = input.read();
                if (b < '0' || '9' < b) break;
                ret *= 10;
                ret += b - '0';
            }
            // If no decimal point, return the integer part
            if (b != '.') return sign * ret;
            // Read the fractional part
            double div = 1;
            b = input.read();
            while ('0' <= b && b <= '9') {
                ret *= 10;
                ret += b - '0';
                div *= 10;
                b = input.read();
            }
            // Return the complete double value
            return sign * ret / div;
        } catch (IOException e) {
            e.printStackTrace();
            return Double.NaN;
        }
    }

    // Method to read the next non-whitespace character from input
    char nextChar() {
        try {
            int b = input.read();
            // Skip whitespace characters
            while (Character.isWhitespace(b)) {
                b = input.read();
            }
