import java.io.BufferedReader;
import java.io.InputStreamReader;
import java.lang.Math;

public class Main {
    public static void main(String[] args) {
        try {
            // Create a BufferedReader to read input from the standard input stream (console)
            BufferedReader stdReader = new BufferedReader(new InputStreamReader(System.in));

            String line; // Variable to store each line of input

            // Continuously read lines from the input until EOF (End of File) is reached
            while((line = stdReader.readLine()) != null) {
                // Parse the input line to a double, representing the radius of a circle
                double r = Double.parseDouble(line);

                // Calculate the area of the circle using the formula: area = π * r^2
                double area = r * r * Math.PI;

                // Calculate the circumference (length) of the circle using the formula: length = 2 * π * r
                double length = 2 * r * Math.PI;

                // Format the area to 6 decimal places as a string
                String circleArea = String.format("%.6f", area);

                // Format the circumference to 6 decimal places as a string
                String circleLength = String.format("%.6f", length);

                // Print the formatted area and circumference separated by a space
                System.out.println(circleArea + " " + circleLength);
            }
            // Close the BufferedReader to release system resources
            stdReader.close();
        } catch(Exception e) {
            // Print the stack trace for debugging purposes if an exception occurs
            e.getStackTrace();
            // Exit the program with a non-zero status to indicate an error
            System.exit(-1);
        }
    }
}

