import java.util.Scanner;

class Main {
    public static void main(String[] args) {
        // Create a Scanner object to read input from the console
        Scanner sc = new Scanner(System.in);

        // Declare variables
        int x;
        String s;

        // Create a Stack object to store operands
        Stack stack = new Stack();

        // Read a line of input from the user
        s = sc.nextLine();

        // Convert the input string to a character array
        char[] str = s.toCharArray();

        // Get the length of the input string
        int len = s.length();

        // Variable to store numbers parsed from the input
        int num = 0;

        // Iterate over each character in the input string
        for (int i = 0; i < len; i++) {
            num = 0;
            boolean f = false;

            // Parse numbers from the input string
            while (i < len && str[i] <= '9' && str[i] >= '0') {
                num *= 10; // Shift the current number left by one decimal place
                num += str[i] - '0'; // Add the current digit to the number
                i++;
                f = true; // Set flag to true indicating a number was found
            }

            // If a number was parsed, push it onto the stack
            if (f) {
                i--; // Adjust index to account for the extra increment in the while loop
                stack.push(num);
            } else if (str[i] == '+' || str[i] == '-' || str[i] == '*' || str[i] == '/') {
                // If an operator is found, pop two operands from the stack
                int b = (int) stack.pop();
                int a = (int) stack.pop();

                // Perform the operation based on the operator and push the result back onto the stack
                switch (str[i]) {
                    case '+': stack.push(a + b); break;
                    case '-': stack.push(a - b); break;
                    case '*': stack.push(a * b); break;
                    case '/': stack.push(a / b); break;
                    default: break;
                }
            }
        }

        // Output the final result from the stack
        System.out.println((int) stack.pop());
    }
}

class Stack {
    // Initialize the top of the stack
    private int top = 0;

    // Array to store stack elements
    private int[] S = new int[200];

    // Maximum size of the stack
    private static final int MAX = 10;

    // Initialize the stack
    public void initialize() {
        top = 0;
    }

    // Check if the stack is empty
    public boolean isEmpty() {
        return top == 0;
    }

    // Check if the stack is full
    public boolean isFull() {
        return top >= MAX - 1;
    }

    // Push an element onto the stack
    public void push(int x) {
        top++;
        S[top] = x;
    }

    // Pop an element from the stack
    public int pop() {
        top--;
        return S[top + 1];
    }
}

